	case errors.Is(err, ErrRevokedTrustAnchor):
		return ExitRevokedTrustAnchor
	case errors.Is(err, ErrTrustDecisionRequired):
		return ExitTrustDecisionRequired
	case errors.Is(err, ErrFirstUseDenied):
