func TestSyncCommand_FrozenFlagRegistered(t *testing.T) {
	cmd := newSyncCommand(RootDeps{})

	flag := cmd.Flags().Lookup("frozen")
	if flag == nil {
		t.Fatal("--frozen flag not registered")
	}
	if flag.Usage != "Disable auto-advance; sync at the pinned commit only" {
		t.Fatalf("unexpected help text: %q", flag.Usage)
	}
}

=== how #43 changed selectWriteScopes (single vs multi write) ===
internal/cli/hierarchy_sync.go:161:func selectWriteScopes(scopes []hierarchy.Scope, includeUser bool) []hierarchy.Scope {
func selectWriteScopes(scopes []hierarchy.Scope, includeUser bool) []hierarchy.Scope {
	out := make([]hierarchy.Scope, len(scopes))
	copy(out, scopes)
	for i := range out {
		out[i].Emit = false
	}

	if includeUser {
		for i := range out {
			if out[i].Level == hierarchy.LevelUser {
				out[i].Emit = true
				return out
			}
		}
		return out
	}

	for i := len(out) - 1; i >= 0; i-- {
		if out[i].Level == hierarchy.LevelUser {
			continue
		}
		out[i].Emit = true
		break
	}

	return out
}

